const i = items[0].json;
const required = ['agent_name', 'action_type', 'result'];
for (const k of required) {
  if (!i[k]) throw new Error(`log_agent_action missing ${k}`);
}
const allowed = ['success','failed','blocked_pending_approval','blocked_missing_info','skipped'];
if (!allowed.includes(i.result)) throw new Error(`invalid result: ${i.result}`);
return [{
  json: {
    agent_name: i.agent_name,
    action_type: i.action_type,
    entity_type: i.entity_type || null,
    entity_id: i.entity_id || null,
    payload: i.payload || {},
    result: i.result,
    error_message: i.error_message || null
  }
}];
